import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { Mail, Phone, MapPin, Send } from 'lucide-react';

const ContactPage = () => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    message: ''
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    // Esto es una simulación. Para enviar correos reales, necesitarías un backend.
    // Por ahora, solo te redirigirá a tu cliente de correo con los datos pre-rellenados.
    const subject = encodeURIComponent(`Mensaje de contacto de AutoVenta - ${formData.name}`);
    const body = encodeURIComponent(`Nombre: ${formData.name}\nEmail: ${formData.email}\nMensaje:\n${formData.message}`);
    const mailtoLink = `mailto:gonzaloacosta5@outlook.com?subject=${subject}&body=${body}`;

    window.location.href = mailtoLink; // Esto intentará abrir el cliente de correo del usuario

    alert('Se abrirá tu cliente de correo para enviar el mensaje. ¡Gracias por contactarnos!');
    setFormData({ name: '', email: '', message: '' });
  };

  return (
    <motion.div
      className="container mx-auto px-4 py-12"
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.6 }}
    >
      <motion.h2
        className="text-5xl font-extrabold text-center mb-8 bg-gradient-to-r from-gray-900 to-gray-600 bg-clip-text text-transparent"
        initial={{ y: -50 }}
        animate={{ y: 0 }}
        transition={{ delay: 0.2, type: 'spring', stiffness: 100 }}
      >
        Contáctanos
      </motion.h2>
      <motion.p
        className="text-lg text-gray-700 max-w-3xl mx-auto mb-12 text-center"
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.4, duration: 0.6 }}
      >
        ¿Tienes alguna pregunta, sugerencia o simplemente quieres charlar sobre coches? ¡Estamos aquí para ayudarte!
      </motion.p>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
        <motion.div
          className="bg-white/90 backdrop-blur-xl border border-gray-200/50 rounded-3xl p-8 shadow-lg"
          initial={{ x: -50, opacity: 0 }}
          animate={{ x: 0, opacity: 1 }}
          transition={{ delay: 0.6, duration: 0.5 }}
        >
          <h3 className="text-3xl font-bold text-gray-900 mb-6">Envíanos un Mensaje</h3>
          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <label htmlFor="name" className="block text-gray-700 font-semibold mb-2">
                Nombre Completo
              </label>
              <input
                type="text"
                id="name"
                name="name"
                value={formData.name}
                onChange={handleChange}
                className="w-full px-5 py-3 border border-gray-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500/30 focus:border-blue-500 transition-all duration-200"
                placeholder="Tu nombre"
                required
              />
            </div>
            <div>
              <label htmlFor="email" className="block text-gray-700 font-semibold mb-2">
                Correo Electrónico
              </label>
              <input
                type="email"
                id="email"
                name="email"
                value={formData.email}
                onChange={handleChange}
                className="w-full px-5 py-3 border border-gray-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500/30 focus:border-blue-500 transition-all duration-200"
                placeholder="tu@ejemplo.com"
                required
              />
            </div>
            <div>
              <label htmlFor="message" className="block text-gray-700 font-semibold mb-2">
                Tu Mensaje
              </label>
              <textarea
                id="message"
                name="message"
                value={formData.message}
                onChange={handleChange}
                rows="6"
                className="w-full px-5 py-3 border border-gray-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500/30 focus:border-blue-500 transition-all duration-200 resize-y"
                placeholder="Escribe tu mensaje aquí..."
                required
              ></textarea>
            </div>
            <motion.button
              type="submit"
              className="w-full bg-blue-600 text-white px-8 py-4 rounded-xl font-semibold shadow-lg hover:bg-blue-700 transition-colors duration-300 flex items-center justify-center gap-2"
              whileHover={{ scale: 1.02 }}
              whileTap={{ scale: 0.98 }}
            >
              <Send className="w-5 h-5" />
              Enviar Mensaje
            </motion.button>
          </form>
        </motion.div>

        <motion.div
          className="bg-white/90 backdrop-blur-xl border border-gray-200/50 rounded-3xl p-8 shadow-lg flex flex-col justify-center"
          initial={{ x: 50, opacity: 0 }}
          animate={{ x: 0, opacity: 1 }}
          transition={{ delay: 0.7, duration: 0.5 }}
        >
          <h3 className="text-3xl font-bold text-gray-900 mb-6">Información de Contacto</h3>
          <div className="space-y-6">
            <div className="flex items-center gap-4">
              <Mail className="w-8 h-8 text-blue-600 flex-shrink-0" />
              <div>
                <p className="text-gray-700 font-semibold">Correo Electrónico:</p>
                <a href="mailto:info@autoventa.com" className="text-blue-600 hover:underline">
                  info@autoventa.com
                </a>
              </div>
            </div>
            <div className="flex items-center gap-4">
              <Phone className="w-8 h-8 text-blue-600 flex-shrink-0" />
              <div>
                <p className="text-gray-700 font-semibold">Teléfono:</p>
                <a href="tel:+1234567890" className="text-blue-600 hover:underline">
                  +1 (234) 567-890
                </a>
              </div>
            </div>
            <div className="flex items-center gap-4">
              <MapPin className="w-8 h-8 text-blue-600 flex-shrink-0" />
              <div>
                <p className="text-gray-700 font-semibold">Dirección:</p>
                <p className="text-gray-700">123 Calle del Motor, Ciudad Automotriz, País</p>
              </div>
            </div>
          </div>
          <motion.div
            className="mt-8 p-6 bg-blue-50 rounded-2xl border border-blue-200 text-blue-800"
            initial={{ scale: 0.9, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            transition={{ delay: 0.8, duration: 0.5 }}
          >
            <p className="font-medium">
              Horario de Atención: Lunes a Viernes, 9:00 AM - 6:00 PM
            </p>
          </motion.div>
        </motion.div>
      </div>
    </motion.div>
  );
};

export default ContactPage;
